-- Bremen — expanded Instagram feed seed.
--
-- Source: https://www.instagram.com/postech.bremen/
-- Captured 82 posts from 7 paginated feed pages.
-- Thumbnails are stored in Supabase Storage bucket images/instagram.

insert into public.entities (
  schema_id,
  slug,
  title,
  subtitle,
  published,
  data
)
values (
  (select id from public.entity_schemas where schema_key = 'section/performance-updates/v1' and active = true),
  'section:performances-updates',
  'Around the stages',
  '공연 전후의 소식',
  true,
  '{"key":"performances-updates","section_type":"entity_post_grid","eyebrow":"Notice board","props":{}}'::jsonb
)
on conflict (slug) do update
set schema_id = excluded.schema_id,
    title = excluded.title,
    subtitle = excluded.subtitle,
    published = excluded.published,
    data = public.entities.data ||
      (excluded.data - 'props') ||
      jsonb_build_object(
        'props',
        coalesce(public.entities.data->'props', '{}'::jsonb) ||
          coalesce(excluded.data->'props', '{}'::jsonb)
      ),
    updated_at = now();

with target as (
  select page_entity.id as page_entity_id, section_entity.id as section_entity_id
  from public.entities page_entity
  join public.entities section_entity
    on section_entity.schema_id in (select id from public.entity_schemas where kind = 'section' and active = true)
   and section_entity.slug = 'section:performances-updates'
  where page_entity.schema_id = (select id from public.entity_schemas where schema_key = 'page/default/v1' and active = true)
    and page_entity.slug = 'page:performances'
)
insert into public.entity_relations (
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  props
)
select
  page_entity_id,
  section_entity_id,
  (select id from public.entity_schemas where schema_key = 'relation/page-section/v1' and active = true),
  'contains_section',
  'sections',
  25,
  '{}'::jsonb
from target
on conflict (from_entity_id, to_entity_id, relation_type, slot) do update
set schema_id = excluded.schema_id,
    sort_order = excluded.sort_order,
    props = excluded.props;

