with relation_seed(child_slug, parent_slug, relation_type, slot, sort_order) as (
  values
    ('instagram-DY1g2MQgYh6', '2026-spring-regular', 'has_photo', 'performance', 10),
    ('instagram-DYd9bp7AWC5', '2026-spring-regular', 'has_post', 'event', 30),
    ('instagram-DYma9VtsJmt', '2026-haemaji', 'has_photo', 'performance', 20),
    ('instagram-DYNBWXXgQGJ', '2026-haemaji', 'has_photo', 'performance', 40),
    ('instagram-DX8-XQiAUC1', '2026-haemaji', 'has_post', 'event', 50)
),
relations as (
  select
    parent.id as from_entity_id,
    child.id as to_entity_id,
    (select id from public.entity_schemas where schema_key = 'relation/default/v1' and active = true) as schema_id,
    relation_seed.relation_type,
    relation_seed.slot,
    relation_seed.sort_order
  from relation_seed
  join public.entities child on child.slug = relation_seed.child_slug
  join public.entities parent on parent.slug = relation_seed.parent_slug
)
insert into public.entity_relations (
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  props
)
select
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  '{}'::jsonb
from relations
on conflict (from_entity_id, to_entity_id, relation_type, slot) do update
set schema_id = excluded.schema_id,
    sort_order = excluded.sort_order,
    props = excluded.props;

with video_seed(video_slug, sort_order) as (
  values
    ('youtube-nWLjvJ2PzJg', 0),
    ('youtube-febCCBym7LI', 1),
    ('youtube-T5mz95e_b9s', 2),
    ('youtube-K-fkChNWiyc', 3),
    ('youtube-Uq4B6_TaTGc', 4),
    ('youtube-GhaDMht6-sM', 5),
    ('youtube-coQtSu5y5AE', 6)
),
relations as (
  select
    performance.id as from_entity_id,
    video.id as to_entity_id,
    (select id from public.entity_schemas where schema_key = 'relation/default/v1' and active = true) as schema_id,
    'has_recording' as relation_type,
    'default' as slot,
    video_seed.sort_order
  from video_seed
  join public.entities performance on performance.slug = '2026-haemaji'
  join public.entities video on video.slug = video_seed.video_slug
  union all
  select
    playlist.id as from_entity_id,
    video.id as to_entity_id,
    (select id from public.entity_schemas where schema_key = 'relation/default/v1' and active = true) as schema_id,
    'contains_video' as relation_type,
    'default' as slot,
    video_seed.sort_order
  from video_seed
  join public.entities playlist on playlist.slug = 'youtube-playlist-PLS8sJ3uGl5j4aEC9BMm7uk4efk4mnwptJ'
  join public.entities video on video.slug = video_seed.video_slug
)
insert into public.entity_relations (
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  props
)
select
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  '{}'::jsonb
from relations
on conflict (from_entity_id, to_entity_id, relation_type, slot) do update
set schema_id = excluded.schema_id,
    sort_order = excluded.sort_order,
    props = excluded.props;

with section_link_seed(section_key, entity_slug, relation_type, slot, sort_order) as (
  values
    ('performances-current-season', '2026-spring-regular', 'item', 'default', 5),
    ('performances-current-season', '2026-haemaji', 'item', 'default', 15),
    ('performances-archive', '2026-spring-regular', 'item', 'season-2026', 5),
    ('performances-archive', '2026-haemaji', 'item', 'season-2026', 15),
    ('videos-by-event', 'youtube-playlist-PLS8sJ3uGl5j4aEC9BMm7uk4efk4mnwptJ', 'item', 'default', 5),
    ('videos-featured', 'youtube-coQtSu5y5AE', 'item', 'default', 5),
    ('videos-library', 'youtube-nWLjvJ2PzJg', 'item', 'default', 5),
    ('videos-library', 'youtube-febCCBym7LI', 'item', 'default', 6),
    ('videos-library', 'youtube-T5mz95e_b9s', 'item', 'default', 7),
    ('videos-library', 'youtube-K-fkChNWiyc', 'item', 'default', 8),
    ('videos-library', 'youtube-Uq4B6_TaTGc', 'item', 'default', 9),
    ('videos-library', 'youtube-GhaDMht6-sM', 'item', 'default', 10),
    ('videos-library', 'youtube-coQtSu5y5AE', 'item', 'default', 11)
),
section_links as (
  select
    section_entity.id as from_entity_id,
    item_entity.id as to_entity_id,
    (select id from public.entity_schemas where schema_key = 'relation/section-entity/v1' and active = true) as schema_id,
    section_link_seed.relation_type,
    section_link_seed.slot,
    section_link_seed.sort_order
  from section_link_seed
  join public.entities section_entity
    on section_entity.schema_id in (select id from public.entity_schemas where kind = 'section' and active = true)
   and section_entity.slug = 'section:' || section_link_seed.section_key
  join public.entities item_entity on item_entity.slug = section_link_seed.entity_slug
)
insert into public.entity_relations (
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  props
)
select
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  '{}'::jsonb
from section_links
on conflict (from_entity_id, to_entity_id, relation_type, slot) do update
set schema_id = excluded.schema_id,
    sort_order = excluded.sort_order,
    props = excluded.props;

