    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-DYd9bp7AWC5', '브레멘 2026-1 정기공연', null, '🥁🎸브레멘 2026-1 정기공연🎹🎤 안녕하세요! 포스텍 대표 밴드 동아리 브레멘입니다. 5월 26일 화요일, 브레멘의 2026년도 1학기 정기공연이 진행됩니다! 누구나 즐길 수 있는 다양한 장르의 곡들을 준비하였으니 많은 관심 부탁드립니다🤩 또한 이번 공연에는 브레멘 26학번의 첫 무대가 준비되어 있습니다! 새내기 브레멘들의 데뷔에 많은 관심과 응원 부탁드립니다😊 🍺공짜 맥주🍺 마시며, 바쁜 학기 중 잠시 마음의 짐을 내려놓고 즐거운 시간 보내다 가세요! 📆공연 시간 : 5월 26일 화요일 9:00PM 🎶공연 장소 : 학생회관 1층 아틀라스 홀 🤘 🥁🎸BREMEN 2026 Spring Concert🎹🎤 Hello! POSTECH''s band club BREMEN is bringing you an exciting c…', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/DYd9bp7AWC5.webp', true, '2026-05-18 05:22:56+00', '{"source":"instagram","shortcode":"DYd9bp7AWC5","media_type":"carousel","source_url":"https://www.instagram.com/postech.bremen/p/DYd9bp7AWC5/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.82787-15/703588328_18076780049638419_2746479818550688545_n.webp?_nc_cat=107&ig_cache_key=Mzg5OTU0Mjc2Mjk0ODkyNDkwNQ%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkNBUk9VU0VMX0lURU0ueHBpZHMuMTQ0MC5zZHIucmVndWxhcl9waG90by5DMyJ9&_nc_ohc=LsuOXrPy_5QQ7kNvwHvR4PT&_nc_oc=AdqO1A8DFoGtHVIlircnjXiSrDYSQDKZL9HaXd_0qIDIvpOe2aifappR7BKQkiKG5D8&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=5N_mpNCjZsplQCs63UeOHg&_nc_ss=7a22e&oh=00_Af-ZjnsF7SCqLvau7g33mwrto_0w40rEdVsiKixBcV9Bjw&oe=6A432F63","storage_path":"instagram/DYd9bp7AWC5.webp","caption":"🥁🎸브레멘 2026-1 정기공연🎹🎤\n\n안녕하세요! 포스텍 대표 밴드 동아리 브레멘입니다.\n5월 26일 화요일, 브레멘의 2026년도 1학기 정기공연이 진행됩니다!\n\n누구나 즐길 수 있는 다양한 장르의 곡들을 준비하였으니 많은 관심 부탁드립니다🤩\n또한 이번 공연에는 브레멘 26학번의 첫 무대가 준비되어 있습니다!\n새내기 브레멘들의 데뷔에 많은 관심과 응원 부탁드립니다😊\n\n🍺공짜 맥주🍺 마시며, 바쁜 학기 중 잠시 마음의 짐을 내려놓고 즐거운 시간 보내다 가세요!\n\n📆공연 시간 : 5월 26일 화요일 9:00PM\n🎶공연 장소 : 학생회관 1층 아틀라스 홀\n\n🤘\n\n🥁🎸BREMEN 2026 Spring Concert🎹🎤\n\nHello! POSTECH''s band club BREMEN is bringing you an exciting concert.\nOn Tuesday May 26th, we will be holding our 2026 Spring Semester Concert!\n\nWe''ve prepared songs from various artists and genres.\nEveryone is welcome, so Come as You Are!🤩\n\nAlso, this day our freshmen members will be having their first performance!\nPlease come and show Love&Cheer for their big debut😊\n\nGrab some 🍺FREE BEER🍺, take a breather from the busy semester, and just enjoy the night with our music!\n\n📆When : Tuesday, May 26th at 9:00PM\n🎶Where : Atlas Hall, 1st floor of the Student Hall","display_date":"05/18","taken_at":"2026-05-18","taken_at_timestamp":1779081776,"content_kind":"event","gallery_include":false,"category":"performance","aspect":"portrait","event_slug":"2026-spring-regular","event_title":"2026 1학기 정기공연","carousel_count":2,"like_count":85,"comment_count":0,"imported_at":"2026-06-25T18:29:39.216Z","source_index":2}'::jsonb),
