    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-DOd4dyCAYDH', 'BREMEN 2025 포스텍카이스트학생대제전 공연', null, '🔥BREMEN 2025 포스텍카이스트학생대제전 공연🔥 안녕하세요!! 포스텍 대표 밴드 동아리 BREMEN 입니다!! 저희 브레멘이 이번 포카전에서 1일차 동아리 교류공연에 참여하게 되었습니다! 많은 관심 부탁드립니다😊🎶 🗓️날짜 : 9월 19일 (금), 6:45 PM 🎸장소 : 카이스트 스포츠컴플렉스 +) 추가로, 9월 18일 (목) 포스텍 대강당에서 열리는 전야제의 응원가 교육과 9월 19일 (금) 낮에 열리는 개막식 합동응원전의 치어로 공연에서 브레멘의 치어로밴드가 함께합니다!! 많이들 즐겨주세요😍 참여 인원 : 김경철 김성은 김신빈 김영재 박건호 서준희 서현진 안동현 양지윤 유규열 이현서 정서영 강승호 김나령 김동규 김예성 남궁성주 문준호 박성현 유규열 이형민 채민경 홍이준 홍준우 황준혁', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/DOd4dyCAYDH.jpg', true, '2025-09-11 15:25:35+00', '{"source":"instagram","shortcode":"DOd4dyCAYDH","media_type":"carousel","source_url":"https://www.instagram.com/postech.bremen/p/DOd4dyCAYDH/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.82787-15/542773409_18047532944638419_6402100396163371745_n.jpg?stp=dst-jpg_e35_tt6&_nc_cat=109&ig_cache_key=MzcxOTM3NzE5NjIzODg4NDE3OQ%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkNBUk9VU0VMX0lURU0ueHBpZHMuMTA4MC5zZHIucmVndWxhcl9waG90by5DMyJ9&_nc_ohc=Raa65Q2D8wkQ7kNvwE_QeLg&_nc_oc=AdrmI0JOqYyAFg5MoH4GpGbkp4QcPMnNZQuEhExRkBO8gyfCcANmyLPHUXN3CfkBcjk&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=JuQnBJZjFqqRcteIWoy3hQ&_nc_ss=7a22e&oh=00_Af92emD4YKPo9i098Jm2OyaK3ywIeVRQONfYR0U4rEwvVA&oe=6A436169","storage_path":"instagram/DOd4dyCAYDH.jpg","caption":"🔥BREMEN 2025 포스텍카이스트학생대제전 공연🔥\n\n안녕하세요!! 포스텍 대표 밴드 동아리 BREMEN 입니다!! 저희 브레멘이 이번 포카전에서 1일차 동아리 교류공연에 참여하게 되었습니다! 많은 관심 부탁드립니다😊🎶\n\n🗓️날짜 : 9월 19일 (금), 6:45 PM\n🎸장소 : 카이스트 스포츠컴플렉스\n\n+) 추가로, 9월 18일 (목) 포스텍 대강당에서 열리는 전야제의 응원가 교육과 9월 19일 (금) 낮에 열리는 개막식 합동응원전의 치어로 공연에서 브레멘의 치어로밴드가 함께합니다!! 많이들 즐겨주세요😍\n\n참여 인원 :\n\n김경철 김성은 김신빈 김영재 박건호 서준희 서현진 안동현 양지윤 유규열 이현서 정서영\n\n강승호 김나령 김동규 김예성 남궁성주 문준호 박성현 유규열 이형민 채민경 홍이준 홍준우 황준혁","display_date":"09/12","taken_at":"2025-09-12","taken_at_timestamp":1757604335,"content_kind":"event","gallery_include":false,"category":"performance","aspect":"portrait","event_slug":"2025-kp-festival","event_title":"2025 포스텍-카이스트 학생대제전","carousel_count":2,"like_count":67,"comment_count":1,"imported_at":"2026-06-25T18:29:39.216Z","source_index":15}'::jsonb),
