    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-C_njXfqhJUs', 'BREMEN 2024 포스텍카이스트학생대제전 공연', null, '🔥BREMEN 2024 포스텍카이스트학생대제전 공연🔥 안녕하세요!! 포스텍 대표 밴드 동아리 BREMEN입니다🎶 저희 브레멘이 이번 포카전에서 1일차 동아리 교류공연에 참여하게 되었습니다! 많은 관심 부탁드립니다😊 🗓️날짜 : 9월 20일 (금) 🎸장소 : 포스텍 대강당 +) 추가로, 9월 19일 (목) 대강당에서 열리는 전야제의 응원가 교육과 9월 20일 (금) 낮에 열리는 개막식 합동응원전의 치어로 공연에서 브레멘의 치어로밴드가 함께합니다!! 많이들 즐겨주세요😍 참여 인원 : 권이준 김동은 김성겸 김준성 김효성 박민규 박성주 서환 신성훈 이지아 정예지 정지성 조연정 최해민 김경철 김성은 김신빈 김영재 박건호 서준희 서현진 신예원 안동현 유규열', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/C_njXfqhJUs.jpg', true, '2024-09-07 13:42:43+00', '{"source":"instagram","shortcode":"C_njXfqhJUs","media_type":"carousel","source_url":"https://www.instagram.com/postech.bremen/p/C_njXfqhJUs/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.82787-15/654808738_18120751606621605_3886968313840415375_n.jpg?stp=dst-jpg_e35_tt6&_nc_cat=105&ig_cache_key=MzQ1MTg4MzE3ODE4NzYyNDUwOA%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkNBUk9VU0VMX0lURU0ueHBpZHMuMTQ0MC5zZHIucmVndWxhcl9waG90by5DMyJ9&_nc_ohc=Zw3C5B-zknwQ7kNvwEmiKBf&_nc_oc=AdpDzQZRd6ZckV0Yxtb4TWQ3V5rTjWTrWycyRRdv_BT-ykyPDhcHcmrjUX2Q_CvasUQ&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=rDERFBjBShSA598Pg_9d0g&_nc_ss=7a22e&oh=00_Af9NRH4tUG90WrSuuVYk-kV99lC_gOCEFHbPLzZrUFg8ZQ&oe=6A4358E4","storage_path":"instagram/C_njXfqhJUs.jpg","caption":"🔥BREMEN 2024 포스텍카이스트학생대제전 공연🔥\n\n안녕하세요!! 포스텍 대표 밴드 동아리 BREMEN입니다🎶 저희 브레멘이 이번 포카전에서 1일차 동아리 교류공연에 참여하게 되었습니다! 많은 관심 부탁드립니다😊\n\n🗓️날짜 : 9월 20일 (금)\n🎸장소 : 포스텍 대강당\n\n+) 추가로, 9월 19일 (목) 대강당에서 열리는 전야제의 응원가 교육과 9월 20일 (금) 낮에 열리는 개막식 합동응원전의 치어로 공연에서 브레멘의 치어로밴드가 함께합니다!! 많이들 즐겨주세요😍\n\n참여 인원 :\n권이준 김동은 김성겸 김준성 김효성 박민규 박성주 서환 신성훈 이지아 정예지 정지성 조연정 최해민\n김경철 김성은 김신빈 김영재 박건호 서준희 서현진 신예원 안동현 유규열","display_date":"09/07","taken_at":"2024-09-07","taken_at_timestamp":1725716563,"content_kind":"event","gallery_include":false,"categ