    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-C7CJpsVh3iJ', 'BREMEN 2024 SPRING 정기공연 SETLIST', null, '🔥 BREMEN 2024 SPRING 정기공연 SETLIST 🔥 안녕하세요! 포스텍 대표 밴드 동아리 브레멘입니다. 학기의 끝이 다가오는 지금, 브레멘의 정기공연이 예정되어 있습니다!! 이번에는 수많은 국내 인디들, Rock, 메탈, JPOP등 다양한 장르와 많은 곡들이 준비되어 있으니, 기대하셔도 좋습니다! 브레멘 친구들 이름 달고 맥주도 마시며 구경하러 오셔서 재밌게 즐기다 가세요! 🎸 날짜: 2024.5.22 (수), 오후 9시 🎹 장소: 학생회관 1층 아틀라스 홀 Rock and Roll 🤘 🔥 BREMEN 2024 SPRING CONCERT SETLIST🔥 Hello! Now that the end of the semester is approaching, a spring concert of Bremen is schedu…', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/C7CJpsVh3iJ.jpg', true, '2024-05-16 15:00:32+00', '{"source":"instagram","shortcode":"C7CJpsVh3iJ","media_type":"carousel","source_url":"https://www.instagram.com/postech.bremen/p/C7CJpsVh3iJ/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.82787-15/654468218_18002162336887937_573779130435271374_n.jpg?stp=dst-jpg_e35_tt6&_nc_cat=104&ig_cache_key=MzM2OTI5NzkwNzk3MDE0MzQ3Nw%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkNBUk9VU0VMX0lURU0ueHBpZHMuMTQ0MC5zZHIucmVndWxhcl9waG90by5DMyJ9&_nc_ohc=3pJUU9Fmj0kQ7kNvwFtAbQc&_nc_oc=Ado-NjxLYOoco8vrXd9thmcYni-Pj3Fi73PIJ6xcCn6w4GbNbNJkmg2Qm48oUjmC8VY&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=4v6NoSU1ccoBCtoZcNOiqw&_nc_ss=7a22e&oh=00_Af-marHQBWNXT0Bnn6riJ0B1u4_ZyhxRxCigvZqL150epA&oe=6A432F7B","storage_path":"instagram/C7CJpsVh3iJ.jpg","caption":"🔥 BREMEN 2024 SPRING 정기공연 SETLIST 🔥\n\n안녕하세요! 포스텍 대표 밴드 동아리 브레멘입니다.\n\n학기의 끝이 다가오는 지금, 브레멘의 정기공연이 예정되어 있습니다!!\n이번에는 수많은 국내 인디들, Rock, 메탈, JPOP등 다양한 장르와 많은 곡들이 준비되어 있으니, 기대하셔도 좋습니다!\n브레멘 친구들 이름 달고 맥주도 마시며 구경하러 오셔서 재밌게 즐기다 가세요!\n\n🎸 날짜: 2024.5.22 (수), 오후 9시\n🎹 장소: 학생회관 1층 아틀라스 홀\n\nRock and Roll 🤘\n\n🔥 BREMEN 2024 SPRING CONCERT SETLIST🔥\n\nHello!\nNow that the end of the semester is approaching, a spring concert of Bremen is scheduled!\nThere are a lot of genres and songs prepared this time, including Korean Indies, Rock, Metal, JPOP, so you can look forward to it!\nIf you have a friend in Bremen, write down their name and grab a free beer. Have fun at concert!\n\n🎸 Date: 2024.05.22(Wednesday) 9PM\n🎹 Place: Atlas Hall, 1st floor of the Student Hall\n\nRock and Roll 🤘","display_date":"05/17","taken_at":"2024-05-17","taken_at_timestamp":1715871632,"content_kind":"setlist","gallery_include":false,"category":"performance","aspect":"portrait","event_slug":"2024-spring-regular","event_title":"24-1 정기공연","carousel_count":5,"like_count":53,"comment_count":0,"imported_at":"2026-06-25T18:29:39.216Z","source_index":38}'::jsonb),
