    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-C6vSLwlBZwV', '2024 해맞이한마당 BREMEN 공연', null, '📢2024 해맞이한마당 BREMEN 공연📢 안녕하세요! 포스텍 대표 밴드동아리 브레멘입니다🤟🎸 축제 마지막날인 금요일 밤에 브레멘 공연이 예정되어 있습니다!! 모두 다같이 따라부를 수 있는 노래 많이 준비했으니 공연에 오셔서 즐겨주시면 감사하겠습니다!!🔥💥 📣 일시: 2024년 5월 10일(금) 오후 8시 35분 📣 장소: 78계단 앞 무대 Vo. 신성훈 정예지 조연정 Gt. 김동은 김효성 박민규 박성주 Ba. 권이준 이지아 Dr. 김준성 정지성 Kb. 김성겸 최해민', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/C6vSLwlBZwV.jpg', true, '2024-05-09 07:09:32+00', '{"source":"instagram","shortcode":"C6vSLwlBZwV","media_type":"p","source_url":"https://www.instagram.com/postech.bremen/p/C6vSLwlBZwV/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.82787-15/635412573_18407047759127727_3934638383362747079_n.jpg?stp=dst-jpg_e35_tt6&_nc_cat=111&ig_cache_key=MzM2Mzk4NzQxOTU4MTIyNjAwNQ%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkZFRUQueHBpZHMuMzAwMC5zZHIucmVndWxhcl9waG90by5DMyJ9&_nc_ohc=UsqVTTlkhaIQ7kNvwFk48ck&_nc_oc=Adpwdn3bHKg-u1rjHhCtLKGGYBmi1Bl81tZsyaVXtovuPbFTtSeaN1s_liUG8kNy6KA&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=4v6NoSU1ccoBCtoZcNOiqw&_nc_ss=7a22e&oh=00_Af96G12mc6eAw5etZCijLq8Mkgt61NEpQ2ubvzEwkJtVAw&oe=6A432A7A","storage_path":"instagram/C6vSLwlBZwV.jpg","caption":"📢2024 해맞이한마당 BREMEN 공연📢\n\n안녕하세요! 포스텍 대표 밴드동아리 브레멘입니다🤟🎸\n\n축제 마지막날인 금요일 밤에 브레멘 공연이 예정되어 있습니다!! 모두 다같이 따라부를 수 있는 노래 많이 준비했으니 공연에 오셔서 즐겨주시면 감사하겠습니다!!🔥💥\n\n📣 일시: 2024년 5월 10일(금) 오후 8시 35분\n📣 장소: 78계단 앞 무대\n\nVo.\n신성훈 정예지 조연정\n\nGt.\n김동은 김효성 박민규 박성주\n\nBa.\n권이준 이지아\n\nDr.\n김준성 정지성\n\nKb.\n김성겸 최해민","display_date":"05/09","taken_at":"2024-05-09","taken_at_timestamp":1715238572,"content_kind":"event","gallery_include":false,"category":"performance","aspect":"portrait","event_slug":"2024-haemaji","event_title":"2024 해맞이한마당","carousel_count":0,"like_count":40,"comment_count":0,"imported_at":"2026-06-25T18:29:39.216Z","source_index":40}'::jsonb),
    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-C31Qs1kplzI', 'BREMEN 신입생 환영 공연', null, '🔥 BREMEN 신입생 환영 공연 🔥 🎶안녕하세요! 포스텍 대표 밴드 동아리 BREMEN입니다! BREMEN 신규모집 마감일에 맞춰서 브레멘이 신입생 환영 공연을 준비했습니다! 급하지만 열심히 준비했으니 많이 오셔서 재밌게 즐겨주시면 감사하겠습니다! 또한 해당 날짜 29일이 신규모집 마감일이기 때문에 많은 지원 부탁드립니다!! 🗓️ 날짜 : 2024.2.29.(목) 오후 9시 🎤 장소 : 학생회관 1층 아틀라스 홀 🔊공연자 명단 SET1 청록(이츠) - 정지성, 권이준, 박성주, 김효성, 조연정 있잖아(아이유) - 김준성, 권이준, 박민규, 박성주, 최해민, 조연정 Runaway Baby(Bruno Mars) - 정지성, 권이준, 김효성, 김동은, 신성훈 Love is Dangerous(터치드) - 정지성, 박성주, 박민규, 최해…', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/C31Qs1kplzI.jpg', true, '2024-02-27 01:17:50+00', '{"source":"instagram","shortcode":"C31Qs1kplzI","media_type":"carousel","source_url":"https://www.instagram.com/postech.bremen/p/C31Qs1kplzI/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.82787-15/654431069_18093801020013776_2672939908407339341_n.jpg?stp=dst-jpg_e35_tt6&_nc_cat=105&ig_cache_key=MzMxMTYyNjU0ODA4OTc5NjA0NQ%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkNBUk9VU0VMX0lURU0ueHBpZHMuMTQ0MC5zZHIucmVndWxhcl9waG90by5DMyJ9&_nc_ohc=DrvGh1KObrAQ7kNvwHLTSH4&_nc_oc=Adr5XDYTxnb3wqEpVC4PmwdSonM-eBV3mXI_nLx8CAJNU59yGFcleQikjR6d7V-dnVI&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=4v6NoSU1ccoBCtoZcNOiqw&_nc_ss=7a22e&oh=00_Af_W4jha3wdjqZOKYltSG_GeUbFsyz3ImMLvK3xDdg9pAw&oe=6A435F29","storage_path":"instagram/C31Qs1kplzI.jpg","caption":"🔥 BREMEN 신입생 환영 공연 🔥\n\n🎶안녕하세요! 포스텍 대표 밴드 동아리 BREMEN입니다!\nBREMEN 신규모집 마감일에 맞춰서 브레멘이 신입생 환영 공연을 준비했습니다!\n\n급하지만 열심히 준비했으니 많이 오셔서 재밌게 즐겨주시면 감사하겠습니다!\n또한 해당 날짜 29일이 신규모집 마감일이기 때문에 많은 지원 부탁드립니다!!\n\n🗓️ 날짜 : 2024.2.29.(목) 오후 9시\n🎤 장소 : 학생회관 1층 아틀라스 홀\n\n🔊공연자 명단\n\nSET1\n청록(이츠) - 정지성, 권이준, 박성주, 김효성, 조연정\n있잖아(아이유) - 김준성, 권이준, 박민규, 박성주, 최해민, 조연정\nRunaway Baby(Bruno Mars) - 정지성, 권이준, 김효성, 김동은, 신성훈\nLove is Dangerous(터치드) - 정지성, 박성주, 박민규, 최해민, 정예지\n비밀번호 486(윤하) - 김준성, 박성주, 조민석, 김효성, 김성겸, 정예지\n박하사탕2(YB) - 정지성, 장서연, 김동은, 박성주, 김성겸, 서환\n\nSET2\n기생충(NELL) - 백지은, 장서연, 안홍상, 배준희, 김성겸, 변우열\n낯선열대(쏜애플) - 백지은, 장서연, 안홍상, 배준희, 김성겸, 변우열\n\nSET3\nlet me go(The Volunteers) - 정지성, 이지아, 박성주, 정예지\n피난(쏜애플) - 김준성, 홍지우, 김효성, 박민규, 서환\n멸종(쏜애플) - 박준혁, 장서연, 박민규, 배준희, 신성훈\n항해(유다빈밴드) - 정지성, 박성주, 김동은, 최해민, 조연정\nDon''t Look Back in Anger(Oasis) - 김준성, 이지아, 김동은, 조민석, 최해민, 서환\n질풍가도(유정석) - 정지성, 이지아, 김효성, 김동은, 김성겸, 신성훈","display_date":"02/27","taken_at":"2024-02-27","taken_at_timestamp":1708996670,"content_kind":"event","gallery_include":false,"category":"performance","aspect":"portrait","event_slug":"2024-spring-welcome","event_title":"2024 신입생 환영공연","carousel_count":4,"like_count":54,"comment_count":1,"imported_at":"2026-06-25T18:29:39.216Z","source_index":41}'::jsonb),
    ((select id from public.entity_schemas where schema_key = 'photo/instagram-grid/v1' and active = true), 'instagram-C3uRuD6JJFZ', '2024 BREMEN 응원가 교육 & 새터 공연', null, '🔥 2024 BREMEN 응원가 교육 & 새터 공연 🔥 즐겨주셔서 감사합니다! 새터 시퍼런봄 - 쏜애플 NO PAIN - 실리카겔 좋지 아니한가 - 유다빈밴드 그대에게 - 넥스트 Vo. 신성훈 서환 변우열 정예지 Gt. 박성주 김효성 박민규 김동은 배준희 안홍상 Ba. 이지아 권이준 장서연 홍지우 Dr. 김준성 정지성 박준혁 백지은 Kb. 김성겸 최해민 홍지우 백지은', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/C3uRuD6JJFZ.jpg', true, '2024-02-24 08:12:03+00', '{"source":"instagram","shortcode":"C3uRuD6JJFZ","media_type":"carousel","source_url":"https://www.instagram.com/postech.bremen/p/C3uRuD6JJFZ/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.82787-15/656217406_18308561833286622_255918071596490402_n.jpg?stp=dst-jpg_e35_tt6&_nc_cat=111&ig_cache_key=MzMwOTY2MDY5NzExNTUyNTg0NA%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkNBUk9VU0VMX0lURU0ueHBpZHMuODEwLnNkci5yZWd1bGFyX3Bob3RvLkMzIn0%3D&_nc_ohc=t4AwZSwfVw8Q7kNvwGJXcB_&_nc_oc=Ado4s6tghw_X5xsopxPK9UxIX_nkwSCfM9-ckYHK58g2RJH7plZhQhEJbmaEU9t9mGc&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=4v6NoSU1ccoBCtoZcNOiqw&_nc_ss=7a22e&oh=00_Af-JKOtTGgiUVImzd8gg9326TU9EZH-fXelx9x-wEb5tYQ&oe=6A434C38","storage_path":"instagram/C3uRuD6JJFZ.jpg","caption":"🔥 2024 BREMEN 응원가 교육 & 새터 공연 🔥\n\n즐겨주셔서 감사합니다!\n\n새터\n시퍼런봄 - 쏜애플\nNO PAIN - 실리카겔\n좋지 아니한가 - 유다빈밴드\n그대에게 - 넥스트\n\nVo.\n신성훈 서환\n변우열 정예지\n\nGt.\n박성주 김효성 박민규 김동은\n배준희 안홍상\n\nBa.\n이지아 권이준\n장서연 홍지우\n\nDr.\n김준성 정지성\n박준혁 백지은\n\nKb.\n김성겸 최해민\n홍지우 백지은","display_date":"02/24","taken_at":"2024-02-24","taken_at_timestamp":1708762323,"content_kind":"notice","gallery_include":true,"category":"performance","aspect":"portrait","event_slug":"2024-orientation","event_title":"2024 새내기새로배움터","carousel_count":10,"like_count":51,"comment_count":0,"imported_at":"2026-06-25T18:29:39.216Z","source_index":42}'::jsonb),
    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-C3fwbp3y1ye', '브레멘 지원 마감 D-10', null, '🚨브레멘 지원 마감 D-10!!! 2024, 새로운 포스테키안이 된 여러분을 위해 브레멘에서 홍보 영상을 제작했습니다! 동아리 탐방에서 보여드렸었고, bremen 유튜브에서도 언제든지 확인 가능합니다! :D 작년 브레멘의 활동을 리뷰하면서 브레멘에 대해 알아보아요! 궁금한 점이 있으면 언제든지 DM주세요~ 지원링크는 프로필에 있습니다!!', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/C3fwbp3y1ye.jpg', true, '2024-02-18 16:53:19+00', '{"source":"instagram","shortcode":"C3fwbp3y1ye","media_type":"reel","source_url":"https://www.instagram.com/postech.bremen/reel/C3fwbp3y1ye/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.71878-15/503322539_1045408540392509_8454112921993011592_n.jpg?stp=dst-jpg_e15_tt6&_nc_cat=111&ig_cache_key=MzMwNTU3MzY1ODEzMTEyNzQ1NA%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkNMSVBTLnhwaWRzLjU0MC5zZHIudmlkZW9fZGVmYXVsdF9jb3Zlcl9mcmFtZS5DMyJ9&_nc_ohc=OgoPnj2sxX0Q7kNvwHEYwot&_nc_oc=Adpd3nmRf-qP3AXTRx6Thq2p00rCozgNSv5HsJXqhm1rnEW01ybvFVFC0RyTvusPSK4&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=4v6NoSU1ccoBCtoZcNOiqw&_nc_ss=7a22e&oh=00_Af-_8k3B_v9PG5UfZK3yIv0ho7jBQP3jQzZEoUj94aWuOA&oe=6A434066","storage_path":"instagram/C3fwbp3y1ye.jpg","caption":"🚨브레멘 지원 마감 D-10!!!\n\n2024, 새로운 포스테키안이 된 여러분을 위해 브레멘에서 홍보 영상을 제작했습니다!\n동아리 탐방에서 보여드렸었고, bremen 유튜브에서도 언제든지 확인 가능합니다! :D\n작년 브레멘의 활동을 리뷰하면서 브레멘에 대해 알아보아요!\n\n궁금한 점이 있으면 언제든지 DM주세요~\n지원링크는 프로필에 있습니다!!","display_date":"02/19","taken_at":"2024-02-19","taken_at_timestamp":1708275199,"content_kind":"promo","gallery_include":false,"category":"daily","aspect":"portrait","event_slug":null,"event_title":null,"carousel_count":0,"like_count":32,"comment_count":2,"imported_at":"2026-06-25T18:29:39.216Z","source_index":43}'::jsonb),
