    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-Cr3bjcFLDIT', 'BREMEN 2023 SPRING 정기공연', null, '🎸BREMEN 2023 SPRING 정기공연🥁 안녕하세요! 포스텍 밴드 동아리 브레멘입니다. 5월 24일, 수요일 저녁 9시에 아틀라스홀에서 브레멘이 공연을 할 예정입니다! 다양한 곡들을 준비하고 있으니, 잠깐 시간내어 즐겨주시면 감사하겠습니다. Peace🤟 On May 24, Bremen, a POSTECH band club will perform at Atlas Hall at 9 p.m. on Wednesday! We''re preparing a variety of songs, so we would be grateful that if you could take a moment to enjoy them. You can check the set list on the poster. Thank you! Peace🤟', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/Cr3bjcFLDIT.jpg', true, '2023-05-05 15:14:25+00', '{"source":"instagram","shortcode":"Cr3bjcFLDIT","media_type":"p","source_url":"https://www.instagram.com/postech.bremen/p/Cr3bjcFLDIT/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.82787-15/625389072_18172700200384480_5887544998555862898_n.jpg?stp=dst-jpg_e35_tt6&_nc_cat=104&ig_cache_key=MzA5NjA2NDQ1MTQyOTU0NDQ2Nw%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkZFRUQueHBpZHMuMTQ0MC5zZHIucmVndWxhcl9waG90by5DMyJ9&_nc_ohc=HnXma4xi7YoQ7kNvwEgU5A1&_nc_oc=AdqhqFscBzosEEbOuFui5mKfE5_YEcMgkwLp-D0a8GgXPBw1F6zoIhBKPsU1UCuEOx8&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=WjKbQ5AtZv3h_Yh8ZzZjEQ&_nc_ss=7a22e&oh=00_Af9TX_wLhrp_wjvxdxEpZ-vgoq4_Qm6KcAFNPOTiTP6j6g&oe=6A435DC6","storage_path":"instagram/Cr3bjcFLDIT.jpg","caption":"🎸BREMEN 2023 SPRING 정기공연🥁\n\n안녕하세요! 포스텍 밴드 동아리 브레멘입니다.\n\n5월 24일, 수요일 저녁 9시에 아틀라스홀에서 브레멘이 공연을 할 예정입니다! \n\n다양한 곡들을 준비하고 있으니, 잠깐 시간내어 즐겨주시면 감사하겠습니다. \n\nPeace🤟\n\nOn May 24, Bremen, a POSTECH band club will perform at Atlas Hall at 9 p.m. on Wednesday! \n\nWe''re preparing a variety of songs, so we would be grateful that if you could take a moment to enjoy them. \n\nYou can check the set list on the poster. Thank you!\n\nPeace🤟","display_date":"05/06","taken_at":"2023-05-06","taken_at_timestamp":