    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-CpP1PByJJP_', 'BREMEN CITY', null, '🔥 BREMEN CITY🔥 🎶안녕하세요! 포스텍 대표 밴드 동아리 BREMEN입니다! BREMEN 신입생 환영 공연이 하루 앞으로 다가왔습니다! 이를 맞이해 BREMEN CITY 영상을 제작하였으니 시청하시고 내일 있을 신입생 환영 공연도 참여 부탁드립니다! 신입생 환영 공연 🗓️ 날짜 : 2023.3.2.(목) 오후 9시 🎤 장소 : 학생회관 4층 ‼️BREMEN 신규 모집 또한 3.4.(토)에 마감되므로 서둘러 지원 부탁드립니다! 지원 링크는 브레멘 인스타그램 프로필에 올라와 있습니다! 자세한 내용은 신규 동아리원 모집 게시물을 참고해 주세요!', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/CpP1PByJJP_.jpg', true, '2023-03-01 13:06:56+00', '{"source":"instagram","shortcode":"CpP1PByJJP_","media_type":"reel","source_url":"https://www.instagram.com/postech.bremen/reel/CpP1PByJJP_/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.71878-15/496927037_1175391741049278_7526917703282996777_n.jpg?stp=dst-jpg_e15_tt6&_nc_cat=108&ig_cache_key=MzA0ODg4OTYwMTkyNTM1NDQ5NQ%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkNMSVBTLnhwaWRzLjQ4MC5zZHIudmlkZW9fZGVmYXVsdF9jb3Zlcl9mcmFtZS5DMyJ9&_nc_ohc=bJx8PtYPjqYQ7kNvwH0WJKy&_nc_oc=Adpk40shVoUHBIxbyqaBh4Mtp6JMyhkZ0DIED8UW3oJWGByMHHShNCp_qINKTsH4SH0&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=WjKbQ5AtZv3h_Yh8ZzZjEQ&_nc_ss=7a22e&oh=00_Af_QQo2z7oO4ae7e3YAp3A_3qZSMN1IPkIqKJI2q5JtNVQ&oe=6A433DF8","storage_path":"instagram/CpP1PByJJP_.jpg","caption":"🔥 BREMEN CITY🔥\n\n🎶안녕하세요! 포스텍 대표 밴드 동아리 BREMEN입니다! BREMEN 신입생 환영 공연이 하루 앞으로 다가왔습니다! 이를 맞이해 BREMEN CITY 영상을 제작하였으니 시청하시고 내일 있을 신입생 환영 공연도 참여 부탁드립니다!\n\n신입생 환영 공연\n🗓️ 날짜 : 2023.3.2.(목) 오후 9시\n🎤 장소 : 학생회관 4층\n\n‼️BREMEN 신규 모집 또한 3.4.(토)에 마감되므로 서둘러 지원 부탁드립니다! 지원 링크는 브레멘 인스타그램 프로필에 올라와 있습니다! 자세한 내용은 신규 동아리원 모집 게시물을 참고해 주세요!","display_date":"03/01","taken_at":"2023-03-01","taken_at_timestamp":1677676016,"content_kind":"promo","gallery_include":false,"category":"performance","aspect":"portrait","event_slug":"2023-spring-welcome","event_title":"2023 신입생 환영공연","carousel_count":0,"like_c