    ((select id from public.entity_schemas where schema_key = 'post/instagram/v1' and active = true), 'instagram-ClPBpsOhMB4', '2022 BREMEN 정기 공연에 초대합니다', null, '📢2022 BREMEN 정기 공연에 초대합니다‼️ 🎶안녕하세요! 포스텍 대표 밴드 동아리 BREMEN입니다! 브레멘이 무려 3년만에 정기공연을 준비하였습니다! 함께 즐길 수 있는 좋은 노래들을 많이 준비했으니 놀러와서 즐겨주세요! 🗓날짜 : 11월 25일 (금) 🕖시간 : 21시 00분 ~ 23시 00분 🎤장소 : 학생회관 아틀라스홀 [이벤트 1] 게시물 공유 이벤트☑️ 1. 브레멘 인스타그램을 팔로우한다! 2. 본 게시글에 좋아요를 누른다! 3. 본 게시글을 @postech.bremen 계정과 친구 3명 이상을 태그하여 스토리에 공유한다! [이벤트 2] 공연 사진 공유 이벤트☑️ 1. 공연을 즐긴다! 2. 공연하는 브레멘을 찍는다! 3. 찍은 사진을 @postech.bremen 계정을 태그하여 스토리에 공유한다! 비공개 계정인 경…', 'https://tyosnoncxaewrjlbnytg.supabase.co/storage/v1/object/public/images/instagram/ClPBpsOhMB4.jpg', true, '2022-11-21 19:30:05+00', '{"source":"instagram","shortcode":"ClPBpsOhMB4","media_type":"carousel","source_url":"https://www.instagram.com/postech.bremen/p/ClPBpsOhMB4/","source_thumbnail_url":"https://scontent-icn2-1.cdninstagram.com/v/t51.82787-15/649878539_18006743441847823_198784414985956151_n.jpg?stp=dst-jpg_e35_tt6&_nc_cat=110&ig_cache_key=Mjk3NjYwNTEzNjE5NTIyMjIyNw%3D%3D.3-ccb7-5&ccb=7-5&_nc_sid=58cdad&efg=eyJ2ZW5jb2RlX3RhZyI6IkNBUk9VU0VMX0lURU0ueHBpZHMuMTA4MC5zZHIucmVndWxhcl9waG90by5DMyJ9&_nc_ohc=MvC5Fm4MT8UQ7kNvwFZod7H&_nc_oc=AdqnMYVvR1GPKhDH09RENmJok83MLYkm9_daCxhLS38MCQ8Tqq3Ylwvk-JqL1KV-xVs&_nc_ad=z-m&_nc_cid=0&_nc_zt=23&_nc_ht=scontent-icn2-1.cdninstagram.com&_nc_gid=WjKbQ5AtZv3h_Yh8ZzZjEQ&_nc_ss=7a22e&oh=00_Af-sZp4vZiDzzWm1c4RkjWt0XK0PjFETE-3d5bdkvCROxw&oe=6A4337AC","storage_path":"instagram/ClPBpsOhMB4.jpg","caption":"📢2022 BREMEN 정기 공연에 초대합니다‼️\n\n🎶안녕하세요! 포스텍 대표 밴드 동아리 BREMEN입니다! 브레멘이 무려 3년만에 정기공연을 준비하였습니다! 함께 즐길 수 있는 좋은 노래들을 많이 준비했으니 놀러와서 즐겨주세요!\n\n🗓날짜 : 11월 25일 (금)\n🕖시간 : 21시 00분 ~ 23시 00분\n🎤장소 : 학생회관 아틀라스홀\n\n[이벤트 1] 게시물 공유 이벤트☑️\n\n  1.  브레멘 인스타그램을 팔로우한다!\n 2.  본 게시글에 좋아요를 누른다!\n 3.  본 게시글을 @postech.bremen 계정과 친구 3명 이상을 태그하여 스토리에 공유한다!\n\n[이벤트 2] 공연 사진 공유 이벤트☑️\n\n  1.  공연을 즐긴다!\n 2.  공연하는 브레멘을 찍는다!\n 3.  찍은 사진을 @postech.bremen 계정을 태그하여 스토리에 공유한다!\n\n비공개 계정인 경우, 스토리 캡쳐 후 브레멘 계정 DM으로 보내주세요!","display_date":"11/22","taken_at":"2022-11-22","taken_at_timestamp":1669059005,"content_kind":"event","gallery_include":false,"category":"performance","aspect":"portrait","event_slug":"2022-fall-regular","event_title":"2022-2 정기공연","carousel_count":6,"like_count":3,"comment_count":0,"imported_at":"2026-06-25T18:29:39.216Z","source_index":68}'::jsonb),
