relations as (
  select
    parent.id as from_entity_id,
    child.id as to_entity_id,
    (select id from public.entity_schemas where schema_key = 'relation/default/v1' and active = true) as schema_id,
    relation_seed.relation_type,
    relation_seed.slot,
    relation_seed.sort_order
  from relation_seed
  join public.entities child on child.slug = relation_seed.child_slug
  join public.entities parent on parent.slug = relation_seed.parent_slug
)
insert into public.entity_relations (
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  props
)
select
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  '{}'::jsonb
from relations
on conflict (from_entity_id, to_entity_id, relation_type, slot) do update
set schema_id = excluded.schema_id,
    sort_order = excluded.sort_order,
    props = excluded.props;

delete from public.entity_relations relation
using public.entities section_entity, public.entities entity
where relation.schema_id = (select id from public.entity_schemas where schema_key = 'relation/section-entity/v1' and active = true)
  and relation.from_entity_id = section_entity.id
  and relation.to_entity_id = entity.id
  and section_entity.schema_id in (select id from public.entity_schemas where kind = 'section' and active = true)
  and section_entity.slug = 'section:photos-gallery'
  and entity.data->>'source' = 'instagram';

with target_section as (
  select section_entity.id as section_entity_id
  from public.entities section_entity
  where section_entity.schema_id in (select id from public.entity_schemas where kind = 'section' and active = true)
    and section_entity.slug = 'section:photos-gallery'
),
ordered as (
  select
    entity.id,
    row_number() over (order by entity.sort_at desc, entity.title) as rank
  from public.entities entity
  where entity.schema_id in (select id from public.entity_schemas where semantic_kind = 'photo' and active = true)
    and entity.data->>'source' = 'instagram'
    and coalesce((entity.data->>'gallery_include')::boolean, false) = true
    and entity.published = true
)
insert into public.entity_relations (
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  props
)
select
  target_section.section_entity_id,
  ordered.id,
  (select id from public.entity_schemas where schema_key = 'relation/section-entity/v1' and active = true),
  'features_photo',
  'gallery',
  ordered.rank * 10,
  '{}'::jsonb
from target_section
cross join ordered
on conflict (from_entity_id, to_entity_id, relation_type, slot) do update
set schema_id = excluded.schema_id,
    sort_order = excluded.sort_order,
    props = excluded.props;

delete from public.entity_relations relation
using public.entities section_entity, public.entities entity
where relation.schema_id = (select id from public.entity_schemas where schema_key = 'relation/section-entity/v1' and active = true)
  and relation.from_entity_id = section_entity.id
  and relation.to_entity_id = entity.id
  and section_entity.schema_id in (select id from public.entity_schemas where kind = 'section' and active = true)
  and section_entity.slug = 'section:performances-updates'
  and entity.data->>'source' = 'instagram';

with target_section as (
  select section_entity.id as section_entity_id
  from public.entities section_entity
  where section_entity.schema_id in (select id from public.entity_schemas where kind = 'section' and active = true)
    and section_entity.slug = 'section:performances-updates'
),
ordered as (
  select
    entity.id,
    coalesce(entity.data->>'content_kind', 'notice') as content_kind,
    row_number() over (order by entity.sort_at desc, entity.title) as rank
  from public.entities entity
  where entity.schema_id in (select id from public.entity_schemas where semantic_kind = 'post' and active = true)
    and entity.data->>'source' = 'instagram'
    and coalesce((entity.data->>'gallery_include')::boolean, false) = false
    and entity.published = true
)
insert into public.entity_relations (
  from_entity_id,
  to_entity_id,
  schema_id,
  relation_type,
  slot,
  sort_order,
  props
)
select
  target_section.section_entity_id,
  ordered.id,
  (select id from public.entity_schemas where schema_key = 'relation/section-entity/v1' and active = true),
  'features_post',
  ordered.content_kind,
  ordered.rank * 10,
  '{}'::jsonb
from target_section
cross join ordered
on conflict (from_entity_id, to_entity_id, relation_type, slot) do update
set schema_id = excluded.schema_id,
    sort_order = excluded.sort_order,
    props = excluded.props;
